// Odhadovaná spotřeba domu v kWh za hodinu.
// Priorita: historický log (avg spotřeba) → config default.
// Pokud je to solární hodina a NIBE topí, přičteme odhadovanou spotřebu NIBE.
function odhadSpotrebyKwh(hodina, frac, level) {
    frac = frac || 1;
    var hist = getHistPrediction(hodina);
    var spotreba;
    if (hist && hist.avgConsumptionKwh > 0 && hist.sampleCount >= 3) {
        // Reálná průměrná spotřeba z logu (zahrnuje vše: NIBE, bojler, auto...)
        spotreba = hist.avgConsumptionKwh;
    } else {
        // Záloha: config odhad (rovnoměrné rozdělení)
        spotreba = C.dayCons / 24;
    }
    // Omezení: max 1/6 denní spotřeby za hodinu (odfiltruje outliers)
    if (spotreba > C.dayCons / 6) spotreba = C.dayCons / 6;
    // NIBE: přičíst v solární hodině vždy (§ 4.9.1 — zrušena podmínka solOverKwh)
    var jeSolarniHodina = hodina >= x.solS && hodina < x.solE;
