}

// Solární zisk pro baterii v dané hodině (kWh → % SOC).
// Kladná hodnota = baterie se nabíjí, záporná = baterie se vybíjí.
function solarniZiskProc(hodina, frac, level) {
    frac = frac || 1;
    var spotreba = odhadSpotrebyKwh(hodina, frac, level);
    var hist = getHistPrediction(hodina);
    // Primárně použít Open Meteo forecast pro danou hodinu
    if (x.fPH[hodina] !== undefined) {
        return ((x.fPH[hodina] - spotreba * frac) * frac * C.chEff / C.kap) * 100;
    }
    // Záloha 1: historický net solar gain (výroba - spotřeba z logu)
    if (hist && hist.sampleCount >= 3 && hist.avgSolarKwh > 0) {
        return ((hist.netSolarGainKwh || 0) * frac * C.chEff / C.kap) * 100;
    }
    // Záloha 2: zbývající solar × solární křivka
    if (x.sC > 0 && x.rS > 0) {
