    }
    if (x.fZ > 0 && solarShare(hodina) > 0) {
        var odhadSolaruZitra = x.fZ * solarShare(hodina);
        return ((odhadSolaruZitra - spotreba * frac) * frac * C.chEff / C.kap) * 100;
