// Pokles SOC v nesluneční hodině dle reálné spotřeby z logu (% SOC za hodinu)
function spotrebovaZtrataProc(hodina, frac) {
    frac = frac || 1;
    var hist = getHistPrediction(hodina);
    var spotreba;
    if (hist && hist.avgConsumptionKwh > 0 && hist.sampleCount >= 3) {
        spotreba = hist.avgConsumptionKwh;
    } else {
        spotreba = x.liveCons || (C.dayCons / 24);
